PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?subgroupLabel(GROUP_CONCAT(DISTINCT ?languageLabel ; SEPARATOR = ", ") AS ?languages)(GROUP_CONCAT(DISTINCT ?religionLabel ; SEPARATOR = ", ") AS ?religions) WHERE {
  VALUES(?subgroup ?subgroupLabel ?country) {(wd:Q1146100 "Chinese Americans" @en wd:Q148)(wd:Q2643509 "Indian Americans" @en wd:Q668)(wd:Q2655978 "Filipino Americans" @en wd:Q928)(wd:Q2657969 "Vietnamese Americans" @en wd:Q881)(wd:Q2650528 "Korean Americans" @en wd:Q884)(wd:Q192917 "Japanese Americans" @en wd:Q17)
  }
  OPTIONAL {
    ?country wdt:P37 ?language .
    ?language rdfs:label ?languageLabel .
    FILTER(LANG(?languageLabel) = "en")
  }
  OPTIONAL {
    ?country wdt:P140 ?religion .
    ?religion rdfs:label ?religionLabel .
    FILTER(LANG(?religionLabel) = "en")
  }
}
GROUP BY ?subgroupLabel
ORDER BY ?subgroupLabel
